import inspect

def validate_api_response(response_data, schema):
    if isinstance(schema, tuple):
        return any(validate_api_response(response_data, sub_schema) for sub_schema in schema)

    if isinstance(schema, dict):
        if not isinstance(response_data, dict):
            return False
        for key, sub_schema in schema.items():
            if key not in response_data:
                return False
            if not validate_api_response(response_data[key], sub_schema):
                return False
        return True

    if isinstance(schema, list):
        if not isinstance(response_data, list):
            return False

        if len(schema) != 1:
            return False 

        item_schema = schema[0]
        for item in response_data:
            if not validate_api_response(item, item_schema):
                return False
        return True

    if inspect.isclass(schema):
        return isinstance(response_data, schema)

    return False
